  ('optometrist-moex-02184', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關脈絡膜功能的敘述，下列何者錯誤？', '["脈絡膜有類似淋巴系統的功能", "血液流經脈絡膜後，約有50%的氧氣被消耗", "脈絡膜血管可受神經調控，改變血管管徑而達到控制血流的作用", "脈絡膜微血管的血液會集中回流到渦靜脈（vortex veins）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02185', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關血液視網膜屏障（blood-retinal barrier）的敘述，下列何者錯誤？', '["內血液視網膜屏障（inner blood-retinal barrier）的主要結構包括網膜血管內皮細胞、繆氏細胞（Müller cell），還有外被細胞（pericyte）", "外血液視網膜屏障（outer blood-retinal barrier）主要結構包括視網膜色素上皮細胞、外境界膜 （external limiting membrane）", "視網膜色素上皮細胞病變時，可能造成視網膜下體液堆積", "繆氏細胞對於維持視網膜正常運作非常重要，主要集中於視網膜周邊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02186', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關玻璃體之敘述，下列何者正確？①主要成份為水份  ②中央區域膠原纖維（collagen fibril）含量', '["玻璃體內無細胞存在", "玻璃體內含有玻尿酸（hyaluronic acid）、鹽類（salt）、 抗壞血酸（ascorbic acid）等物質", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02187', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '視交叉前的視覺路徑中最主要的動脈血液供應來自於下列何者？', '["肋頸幹（costocervical trunk）", "椎動脈（vertebral artery）", "甲狀腺頸幹（thyrocervical trunk）", "總頸動脈（common carotid artery）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02188', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者血管系統可支配外側膝狀體（lateral geniculate body）的循環？①大腦中動脈（middle cerebral', '["大腦前動脈（anterior cerebral artery）", "前脈絡叢動脈（anterior choroidal artery）", "外頸動脈（external carotid artery）", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02189', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '2歲的早產兒因腦傷而有視野缺損，經核磁共振檢查發現腦傷的位置在右側的枕葉（occipital lobe）。 眼球及視神經構造正常。最有可能的視野缺損表現為何？瞳孔對光的反應如何？', '["左側半側偏盲，左眼瞳孔照光有收縮反應，右眼瞳孔照光沒有收縮反應", "左側半側偏盲，雙眼瞳孔照光均有收縮反應", "右側半側偏盲，雙眼瞳孔照光均有收縮反應", "右側半側偏盲，右眼瞳孔照光有收縮反應，左眼瞳孔照光沒有收縮反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02190', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '腦部中樞控制瞳孔大小、調節（accommodation）的運動神經元，最接近控制下列那一條眼外肌的腦 神經核？', '["下斜肌", "上斜肌", "外直肌", "內斜肌"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02191', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關立體感的敘述，下列何者錯誤？', '["立體感大約在3-5個月大即開始發育，可以由視覺誘發電位（VEP）或是行為研究（behavior methods） 偵測到", "到了5-6 歲，小孩的立體敏銳度（disparity sensitivity）已發育至成人程度", "學齡前的立體感檢查可以篩檢出斜視或是弱視的小朋友", "單眼的病患可以光影、物體大小等線索在日常生活中判斷距離及深度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02192', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關虹膜的神經支配的敘述，下列何者錯誤？', '["虹膜的神經支配包含交感神經和副交感神經", "瞳孔括約肌由動眼神經的副交感神經核（Edinger-Westphal nucleus）的副交感神經纖維支配", "副交感神經在睫狀神經節中發生突觸後，節後纖維透過視神經傳遞到眼球", "瞳孔擴張肌由上頸部交感神經節的交感神經節後纖維支配，透過短睫狀神經和長睫狀神經到達眼球"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02193', 'optometrist', 'optometrist-moex-108-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列有關於眼外肌之敘述何者正確？', '["四條直肌在眼球之附著點呈現螺旋型，稱為Tillaux氏螺旋（spiral of Tillaux），其中內直肌之附著 點離輪部（limbus）最近", "四條直肌之神經支配皆來自於第三對腦神經，也就是動眼神經", "所有眼外肌之起端皆源自於外眼肌腱環（the annulus of Zinn）", "上斜肌與下斜肌之神經支配皆來自於滑車神經"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "af4f311a2973", "answer_pdf_sha1": "e6bf67c4f8da", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
